def threeSum(nums):
    nums.sort()
    res = []
    for i, a in enumerate(nums):
        if i and a == nums[i - 1]:
            continue
        l, r = i + 1, len(nums) - 1
        while l < r:
            s = a + nums[l] + nums[r]
            if s < 0:
                l += 1
            elif s > 0:
