def trap(h):
    l, r = 0, len(h) - 1
    lmax = rmax = total = 0
    while l < r:
        if h[l] < h[r]:
            lmax = max(lmax, h[l])
            total += lmax - h[l]
            l += 1
        else:
            rmax = max(rmax, h[r])
            total += rmax - h[r]
            r -= 1
    return total

