def checkInclusion(s1, s2):
    if len(s1) > len(s2):
        return False
    need = Counter(s1)
    have = Counter(s2[:len(s1)])
    if have == need:
        return True
    for i in range(len(s1), len(s2)):
        have[s2[i]] += 1
        have[s2[i - len(s1)]] -= 1
        if have[s2[i - len(s1)]] == 0:
            del have[s2[i - len(s1)]]
        if have == need:
            return True
    return False

