    l, r = 0, m
    while l <= r:
        i = (l + r) // 2
        j = half - i
        al = a[i - 1] if i else -float('inf')
        ar = a[i] if i < m else float('inf')
        bl = b[j - 1] if j else -float('inf')
        br = b[j] if j < n else float('inf')
        if al <= br and bl <= ar:
            if (m + n) % 2:
