def isBalanced(root):
    def height(n):
        if not n:
            return 0
        l = height(n.left)
        if l == -1: return -1
        r = height(n.right)
        if r == -1 or abs(l - r) > 1: return -1
        return 1 + max(l, r)
    return height(root) != -1

