def buildTree(preorder, inorder):
    idx = {v: i for i, v in enumerate(inorder)}
    pre = iter(preorder)
    def build(l, r):
        if l > r:
            return None
        v = next(pre)
        node = TreeNode(v)
        node.left = build(l, idx[v] - 1)
        node.right = build(idx[v] + 1, r)
        return node
    return build(0, len(inorder) - 1)

def maxPathSum(root):
    best = -float('inf')
    def dfs(n):
        nonlocal best
        if not n:
            return 0
        l = max(dfs(n.left), 0)
        r = max(dfs(n.right), 0)
        best = max(best, n.val + l + r)
        return n.val + max(l, r)
    dfs(root)
    return best

class Codec:
    def serialize(self, root):
        vals = []
        def dfs(n):
            if not n:
                vals.append('#'); return
            vals.append(str(n.val))
            dfs(n.left); dfs(n.right)
        dfs(root)
        return ','.join(vals)

    def deserialize(self, data):
        it = iter(data.split(','))
        def dfs():
            v = next(it)
            if v == '#': return None
            n = TreeNode(int(v))
            n.left, n.right = dfs(), dfs()
            return n
        return dfs()

class Trie:
    def __init__(self):
        self.children = {}
        self.end = False

    def insert(self, w):
        cur = self
        for c in w:
            cur = cur.children.setdefault(c, Trie())
        cur.end = True

    def search(self, w):
        cur = self._walk(w)
        return bool(cur) and cur.end

    def startsWith(self, p):
        return self._walk(p) is not None

    def _walk(self, w):
        cur = self
        for c in w:
            if c not in cur.children:
                return None
            cur = cur.children[c]
        return cur

class WordDictionary:
    def __init__(self):
        self.root = {}

    def addWord(self, w):
        cur = self.root
        for c in w:
            cur = cur.setdefault(c, {})
        cur['$'] = True

    def search(self, w):
        def dfs(node, i):
            if i == len(w):
                return node.get('$', False)
            c = w[i]
            if c == '.':
                return any(dfs(child, i + 1) for k, child in node.items() if k != '$')
            return c in node and dfs(node[c], i + 1)
        return dfs(self.root, 0)

def findWords(board, words):
    root = {}
    for w in words:
        cur = root
        for c in w:
            cur = cur.setdefault(c, {})
        cur['$'] = w
    rows, cols = len(board), len(board[0])
    out = []
    def dfs(r, c, node):
        ch = board[r][c]
        if ch not in node:
            return
        nxt = node[ch]
        if '$' in nxt:
            out.append(nxt.pop('$'))
        board[r][c] = '#'
        for dr, dc in ((1, 0), (-1, 0), (0, 1), (0, -1)):
            nr, nc = r + dr, c + dc
            if 0 <= nr < rows and 0 <= nc < cols:
                dfs(nr, nc, nxt)
        board[r][c] = ch
    for r in range(rows):
        for c in range(cols):
            dfs(r, c, root)
    return out

